app.post("/api/v1/admin/auth/login",{config:{rateLimit:{max:6,timeWindow:"15 minutes"}}},async(req,reply)=>{const body=z.object({email:z.string().email(),password:z.string(),deviceId:z.string().min(8)}).parse(req.body);const user=await verifyPasswordAndTrack(prisma,body.email,body.password);if(!user||user.status!=="ACTIVE"||!isAdminRole(user.role))return sendError(reply,req.id,401,"INVALID_CREDENTIALS","Email or password is incorrect");const accessToken=await signAccess(user.id,user.role);const csrf=opaqueToken();reply.setCookie(config.ADMIN_COOKIE_NAME,accessToken,{httpOnly:true,secure:config.NODE_ENV==="production",sameSite:adminCookieSameSite,path:"/",maxAge:config.ACCESS_TOKEN_TTL_SECONDS});reply.setCookie(config.ADMIN_CSRF_COOKIE_NAME,csrf,{httpOnly:false,secure:config.NODE_ENV==="production",sameSite:adminCookieSameSite,path:"/",maxAge:config.ACCESS_TOKEN_TTL_SECONDS});await prisma.adminAuditLog.create({data:{actorUserId:user.id,action:"ADMIN_LOGIN",targetType:"SESSION",requestId:req.id,ipHash:ipHash(req)}});return {accessToken,user:publicUser(user),csrfToken:csrf}});
app.post("/api/v1/admin/auth/logout",{preHandler:[authenticate,requireCsrf]},async(req,reply)=>{reply.clearCookie(config.ADMIN_COOKIE_NAME,{path:"/"});reply.clearCookie(config.ADMIN_CSRF_COOKIE_NAME,{path:"/"});await audit(req as AuthRequest,"ADMIN_LOGOUT","SESSION");return reply.code(204).send()});
app.get("/api/v1/admin/auth/me",{preHandler:authenticate},async(req,reply)=>{const auth=(req as AuthRequest).auth;if(!isAdminRole(auth.role))return sendError(reply,req.id,403,"FORBIDDEN","Administrator access required");const user=await prisma.user.findUniqueOrThrow({where:{id:auth.sub}});return {...publicUser(user),accessToken:await signAccess(user.id,user.role)}});
app.get("/api/v1/admin/users",{preHandler:requirePermission("users:manage")},async()=>prisma.user.findMany({select:{id:true,email:true,displayName:true,role:true,status:true,accessRestricted:true,emailVerifiedAt:true,createdAt:true,movieAccess:{select:{movieId:true}},collectionAccess:{select:{collectionId:true}}},orderBy:{createdAt:"desc"},take:100}));
app.post("/api/v1/admin/users",{preHandler:[requirePermission("users:manage"),requireCsrf]},async(req,reply)=>{const body=userWriteBody.extend({email:z.string().email(),displayName:z.string().min(2).max(80),password:z.string().min(12).max(128)}).parse(req.body);const user=await prisma.user.create({data:{email:body.email.toLowerCase(),displayName:body.displayName,passwordHash:await argon2.hash(body.password,{type:argon2.argon2id}),role:body.role??"VIEWER",status:body.status??"ACTIVE",accessRestricted:body.accessRestricted??true,emailVerifiedAt:new Date()}});if(body.access)await replaceUserAccess(user.id,body.access);await audit(req as AuthRequest,"USER_CREATED","USER",user.id,{email:user.email,role:user.role});return reply.code(201).send(await prisma.user.findUniqueOrThrow({where:{id:user.id},select:{id:true,email:true,displayName:true,role:true,status:true,accessRestricted:true,emailVerifiedAt:true,createdAt:true,movieAccess:{select:{movieId:true}},collectionAccess:{select:{collectionId:true}}}}))});
app.patch("/api/v1/admin/users/:id",{preHandler:[requirePermission("users:manage"),requireCsrf]},async(req)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;const body=userWriteBody.parse(req.body);const data:Prisma.UserUpdateInput={email:body.email?.toLowerCase(),displayName:body.displayName,role:body.role,status:body.status,accessRestricted:body.accessRestricted,passwordHash:body.password?await argon2.hash(body.password,{type:argon2.argon2id}):undefined};const user=await prisma.user.update({where:{id},data});if(body.status&&body.status!=="ACTIVE")await prisma.refreshSession.updateMany({where:{userId:id,revokedAt:null},data:{revokedAt:new Date()}});if(body.access)await replaceUserAccess(id,body.access);await audit(req as AuthRequest,"USER_UPDATED","USER",id,{fields:Object.keys(body)});return prisma.user.findUniqueOrThrow({where:{id},select:{id:true,email:true,displayName:true,role:true,status:true,accessRestricted:true,emailVerifiedAt:true,createdAt:true,movieAccess:{select:{movieId:true}},collectionAccess:{select:{collectionId:true}}}})});
app.patch("/api/v1/admin/users/:id/status",{preHandler:[requirePermission("users:manage"),requireCsrf]},async(req,reply)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;const body=z.object({status:z.enum(["ACTIVE","SUSPENDED","DISABLED"])}).parse(req.body);const user=await prisma.user.update({where:{id},data:{status:body.status}});if(body.status!=="ACTIVE")await prisma.refreshSession.updateMany({where:{userId:id,revokedAt:null},data:{revokedAt:new Date()}});await audit(req as AuthRequest,"USER_STATUS_CHANGED","USER",id,{status:body.status});return publicUser(user)});
app.delete("/api/v1/admin/users/:id",{preHandler:[requirePermission("users:manage"),requireCsrf]},async(req,reply)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;const auth=(req as AuthRequest).auth;if(id===auth.sub)return sendError(reply,req.id,400,"USER_DELETE_SELF","You cannot delete your own admin account");const user=await prisma.user.findUnique({where:{id}});if(!user)return sendError(reply,req.id,404,"USER_NOT_FOUND","User not found");await prisma.$transaction(async(tx)=>{await tx.refreshSession.deleteMany({where:{userId:id}});await tx.passwordResetToken.deleteMany({where:{userId:id}});await tx.emailVerificationToken.deleteMany({where:{userId:id}});await tx.playbackSession.deleteMany({where:{userId:id}});await tx.watchProgress.deleteMany({where:{userId:id}});await tx.watchHistory.deleteMany({where:{userId:id}});await tx.myListItem.deleteMany({where:{userId:id}});await tx.userMovieAccess.deleteMany({where:{userId:id}});await tx.userCollectionAccess.deleteMany({where:{userId:id}});await tx.user.delete({where:{id}})});await audit(req as AuthRequest,"USER_DELETED","USER",id,{email:user.email});return reply.code(204).send()});
