app.delete("/api/v1/admin/movies/:id",{preHandler:[requirePermission("catalog:write"),requireCsrf]},async(req,reply)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;const movie=await prisma.movie.findUnique({where:{id},include:{assets:true}});if(!movie)return sendError(reply,req.id,404,"MOVIE_NOT_FOUND","Movie not found");const assetIds=movie.assets.map(asset=>asset.id);await prisma.$transaction(async(tx)=>{await tx.collectionItem.deleteMany({where:{movieId:id}});await tx.myListItem.deleteMany({where:{catalogId:id}});if(assetIds.length){await tx.playbackSession.deleteMany({where:{videoAssetId:{in:assetIds}}});await tx.watchProgress.deleteMany({where:{videoAssetId:{in:assetIds}}});await tx.watchHistory.deleteMany({where:{videoAssetId:{in:assetIds}}});await tx.upload.deleteMany({where:{videoAssetId:{in:assetIds}}});await tx.videoRendition.deleteMany({where:{videoAssetId:{in:assetIds}}});await tx.videoAsset.deleteMany({where:{id:{in:assetIds}}})}await tx.movie.delete({where:{id}})});for(const asset of movie.assets){for(const key of new Set([asset.sourceStorageKey,asset.manifestStorageKey].filter(Boolean) as string[])){const filePath=storagePathFor(key);if(filePath)await unlink(filePath).catch(()=>undefined)}}await audit(req as AuthRequest,"MOVIE_DELETED","MOVIE",id,{title:movie.title,assetCount:assetIds.length});return reply.code(204).send()});
