app.get("/api/v1/admin/video-assets/:id/preview",async(req,reply)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;const query=z.object({token:z.preprocess(value=>value===""?undefined:value,z.string().min(20).optional())}).parse(req.query);if(query.token){try{const payload=await verifyAccess(query.token);if(!payload.sub||typeof payload.role!=="string"||!isAdminRole(payload.role as Role))return sendError(reply,req.id,403,"FORBIDDEN","Administrator access required");(req as AuthRequest).auth={sub:payload.sub,role:payload.role as Role}}catch{return sendError(reply,req.id,401,"TOKEN_INVALID","Session expired")}}else{await authenticate(req,reply);if(reply.sent)return;if(!isAdminRole((req as AuthRequest).auth.role))return sendError(reply,req.id,403,"FORBIDDEN","Administrator access required")}const asset=await prisma.videoAsset.findUnique({where:{id},include:{movie:true,episode:true}});const previewKey=asset?.manifestStorageKey??asset?.sourceStorageKey;if(!previewKey)return sendError(reply,req.id,404,"PREVIEW_NOT_FOUND","Preview file is unavailable");const filePath=storagePathFor(previewKey);if(!filePath)return sendError(reply,req.id,400,"PREVIEW_INVALID","Preview path is invalid");let size=0;try{size=(await stat(filePath)).size}catch{return sendError(reply,req.id,404,"PREVIEW_NOT_FOUND","Preview file is unavailable")};const range=req.headers.range;reply.header("accept-ranges","bytes");reply.header("cache-control","private, max-age=60");reply.header("content-type",contentTypeFor(previewKey));if(range){const match=range.match(/bytes=(\d*)-(\d*)/);const startRaw=match?.[1],endRaw=match?.[2];const start=startRaw?Number(startRaw):0;const end=endRaw?Math.min(Number(endRaw),size-1):size-1;if(!Number.isFinite(start)||!Number.isFinite(end)||start<0||end<start||start>=size)return reply.code(416).header("content-range",`bytes */${size}`).send();reply.code(206).header("content-range",`bytes ${start}-${end}/${size}`).header("content-length",String(end-start+1));return reply.send(createReadStream(filePath,{start,end}))}reply.header("content-length",String(size));return reply.send(createReadStream(filePath))});
