app.post("/api/v1/admin/uploads/direct",{preHandler:[requirePermission("catalog:write"),requireCsrf],config:{rateLimit:{max:8,timeWindow:"15 minutes"}}},async(req,reply)=>{const uploadIdHeader=typeof req.headers["x-upload-id"]==="string"?req.headers["x-upload-id"]:"";const requestedUploadId=z.string().uuid().safeParse(uploadIdHeader).success?uploadIdHeader:undefined;const parts=req.parts();let title="",synopsis="",maturityRating="";let file:{filename:string;mimetype:string;bytes:number;storageKey:string;previewStorageKey:string;durationSeconds:number}|undefined;for await(const part of parts){if(part.type==="field"){const value=String(part.value??"");if(part.fieldname==="title")title=value;if(part.fieldname==="synopsis")synopsis=value;if(part.fieldname==="maturityRating")maturityRating=value;continue}if(part.fieldname!=="file")continue;const uploadId=requestedUploadId??randomUUID();const safeName=part.filename.replace(/[^a-zA-Z0-9._-]/g,"_");const storageKey=`uploads/${uploadId}-${safeName}`;const previewStorageKey=`previews/${uploadId}.mp4`;const destination=path.join(storageRoot,storageKey);const previewDestination=path.join(storageRoot,previewStorageKey);try{await mkdir(path.dirname(destination),{recursive:true});await mkdir(path.dirname(previewDestination),{recursive:true});let bytes=0;part.file.on("data",(chunk:Buffer)=>bytes+=chunk.length);await pipeline(part.file,createWriteStream(destination));const durationSeconds=Math.round(await probeDurationSeconds(destination)??0);rememberConversion(uploadId,"Converting preview",0);try{await transcodePreview(destination,previewDestination,progress=>rememberConversion(uploadId,"Converting preview",progress));rememberConversion(uploadId,"Ready",100);forgetConversionLater(uploadId)}catch(error){rememberConversion(uploadId,"Preview conversion failed",100);forgetConversionLater(uploadId);req.log.warn({err:error,filename:part.filename},"preview transcode failed; falling back to source file")}file={filename:part.filename,mimetype:part.mimetype,bytes,storageKey,previewStorageKey:await stat(previewDestination).then(()=>previewStorageKey).catch(()=>storageKey),durationSeconds}}catch(error){req.log.error({err:error,storageRoot},"upload storage write failed");return sendError(reply,req.id,500,"UPLOAD_STORAGE_UNWRITABLE",`Upload storage is not writable at ${storageRoot}. Set STORAGE_LOCAL_ROOT to a writable volume.`)}}if(!title.trim()||!file)return sendError(reply,req.id,400,"UPLOAD_INVALID","Title and video file are required");const movie=await prisma.movie.create({data:{title:title.trim(),synopsis:synopsis.trim()||"Uploaded from admin console.",slug:`${slugify(title)}-${Date.now()}`,status:"DRAFT",maturityRating:maturityRating.trim()||undefined,assets:{create:{state:"READY",sourceStorageKey:file.storageKey,manifestStorageKey:file.previewStorageKey,durationSeconds:file.durationSeconds||undefined,uploads:{create:{storageKey:file.storageKey,bytesExpected:file.bytes,bytesReceived:file.bytes,status:"COMPLETED"}}}}},include:{assets:true}});await audit(req as AuthRequest,"DIRECT_UPLOAD_COMPLETED","MOVIE",movie.id,{filename:file.filename,bytes:file.bytes,mimetype:file.mimetype,previewStorageKey:file.previewStorageKey,durationSeconds:file.durationSeconds});return reply.code(201).send(movie)});
app.post("/api/v1/admin/uploads/:id/parts",{preHandler:[requirePermission("catalog:write"),requireCsrf]},async(req)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;const body=z.object({partCount:z.number().int().min(1).max(1000)}).parse(req.body);const parts=Array.from({length:body.partCount},(_,i)=>({partNumber:i+1,uploadUrl:`/api/v1/admin/uploads/${id}/parts/${i+1}`}));const upload=await prisma.upload.update({where:{id},data:{status:"PARTS_ISSUED",parts}});await audit(req as AuthRequest,"UPLOAD_PARTS_ISSUED","UPLOAD",id,{partCount:body.partCount});return {...upload,parts}});
app.post("/api/v1/admin/uploads/:id/complete",{preHandler:[requirePermission("catalog:write"),requireCsrf]},async(req,reply)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;const body=z.object({bytesReceived:z.number().int().positive(),durationSeconds:z.number().int().positive().optional(),manifestStorageKey:z.string().min(1).optional()}).parse(req.body);const upload=await prisma.upload.findUnique({where:{id},include:{videoAsset:true}});if(!upload)return sendError(reply,req.id,404,"UPLOAD_NOT_FOUND","Upload not found");if(BigInt(body.bytesReceived)>upload.bytesExpected)return sendError(reply,req.id,400,"UPLOAD_TOO_LARGE","Received bytes exceed declared upload size");const asset=await prisma.$transaction(async(tx)=>{await tx.upload.update({where:{id},data:{status:"COMPLETED",bytesReceived:body.bytesReceived}});return tx.videoAsset.update({where:{id:upload.videoAssetId},data:{state:body.manifestStorageKey?"READY":"QUEUED",durationSeconds:body.durationSeconds,manifestStorageKey:body.manifestStorageKey}})});if(!body.manifestStorageKey)await processingQueue.add("transcode",{assetId:asset.id,input:upload.storageKey,output:`${upload.videoAssetId}/manifest.m3u8`},{attempts:3,backoff:{type:"exponential",delay:30_000}});await audit(req as AuthRequest,"UPLOAD_COMPLETED","UPLOAD",id,{queued:!body.manifestStorageKey});return asset});
