app.get("/api/v1/catalog",{preHandler:authenticate},async(req)=>{const scope=await userAccessScope((req as AuthRequest).auth.sub);const [collections,movies]=await Promise.all([prisma.collection.findMany({where:{published:true,...(scope?{id:{in:[...scope.collectionIds]}}:{})},orderBy:[{parentId:"asc"},{sortOrder:"asc"}],include:{parent:true,items:{orderBy:{sortOrder:"asc"},include:{movie:{include:{assets:true}},series:true}}}}),prisma.movie.findMany({where:{status:"PUBLISHED",...(scope?{id:{in:[...scope.movieIds]}}:{})},include:{assets:true},orderBy:[{featured:"desc"},{updatedAt:"desc"}],take:50})]);await ensureMovieDurations([...(movies as MovieWithAssets[]),...(collections.flatMap(collection=>collection.items.map(item=>item.movie).filter(Boolean)) as MovieWithAssets[])]);const collectionRails=collections.map(collection=>({id:collection.id,name:collection.parent?`${collection.parent.name} / ${collection.name}`:collection.name,slug:collection.slug,parentId:collection.parentId,parentName:collection.parent?.name??null,items:collection.items.flatMap<CatalogCard>(item=>{if(item.movie&&(!scope||scope.movieIds.has(item.movie.id))&&item.movie.status==="PUBLISHED"&&isCurrentlyAvailable(item.movie)&&movieHasReadyAsset(item.movie))return [toMovieCard(item.movie)];if(item.series&&item.series.status==="PUBLISHED")return [toSeriesCard(item.series)];return []})})).filter(rail=>rail.items.length>0);const collectionMovieIds=new Set(collectionRails.flatMap(rail=>rail.items.filter(item=>item.kind==="MOVIE").map(item=>item.id)));const movieItems=movies.filter(movie=>isCurrentlyAvailable(movie)&&movieHasReadyAsset(movie)&&!collectionMovieIds.has(movie.id)).map(toMovieCard);return {rails:[...collectionRails,...(movieItems.length?[{id:"default-videos",name:"Videos",slug:"videos",parentId:null,parentName:null,items:movieItems}]:[])]}});
app.get("/api/v1/search",{preHandler:authenticate},async(req)=>{const auth=(req as AuthRequest).auth;const scope=await userAccessScope(auth.sub);const q=z.object({q:z.string().min(2).max(100),genre:z.string().optional()}).parse(req.query);const [movies,collections]=await Promise.all([prisma.movie.findMany({where:{status:"PUBLISHED",...(scope?{id:{in:[...scope.movieIds]}}:{}),genres:q.genre?{has:q.genre}:undefined,OR:[{title:{contains:q.q,mode:"insensitive"}},{synopsis:{contains:q.q,mode:"insensitive"}},{tags:{has:q.q}}]},include:{assets:true},take:30}),prisma.collection.findMany({where:{published:true,...(scope?{id:{in:[...scope.collectionIds]}}:{}),OR:[{name:{contains:q.q,mode:"insensitive"}},{slug:{contains:q.q,mode:"insensitive"}}]},include:{items:{include:{movie:{include:{assets:true}}}}},take:10})]);const folderMovies=collections.flatMap(collection=>collection.items.flatMap(item=>item.movie?[item.movie]:[]));const allMovies=[...movies,...folderMovies].filter((movie,index,self)=>self.findIndex(item=>item.id===movie.id)===index);await ensureMovieDurations(allMovies as MovieWithAssets[]);return allMovies.filter(movie=>(!scope||scope.movieIds.has(movie.id))&&movie.status==="PUBLISHED"&&isCurrentlyAvailable(movie)&&movieHasReadyAsset(movie)).map(toMovieCard)});
app.post("/api/v1/offline/downloads",{preHandler:authenticate,config:{rateLimit:{max:30,timeWindow:"1 minute"}}},async(req,reply)=>{const auth=(req as AuthRequest).auth;const body=z.object({videoId:z.string().uuid(),deviceId:z.string().min(8)}).parse(req.body);const user=await prisma.user.findUniqueOrThrow({where:{id:auth.sub}});if(user.status!=="ACTIVE")return sendError(reply,req.id,403,"ACCOUNT_BLOCKED","Offline downloads unavailable");const asset=await prisma.videoAsset.findFirst({where:{state:"READY",OR:[{id:body.videoId},{movieId:body.videoId},{episodeId:body.videoId}]},include:{movie:true,episode:true}});if(!asset||!asset.manifestStorageKey)return sendError(reply,req.id,404,"VIDEO_UNAVAILABLE","Video is unavailable for offline download");if(asset.movie&&!(await canAccessMovie(user.id,asset.movie.id)))return sendError(reply,req.id,403,"TITLE_FORBIDDEN","This user is not allowed to watch this video");if(asset.movie&&(asset.movie.status!=="PUBLISHED"||!isCurrentlyAvailable(asset.movie)))return sendError(reply,req.id,403,"TITLE_UNAVAILABLE","This title is unavailable");if(asset.episode&&asset.episode.status!=="PUBLISHED")return sendError(reply,req.id,403,"TITLE_UNAVAILABLE","This episode is unavailable");const filePath=storagePathFor(asset.manifestStorageKey);if(!filePath)return sendError(reply,req.id,400,"DOWNLOAD_INVALID","Download path is invalid");let bytesExpected=0;try{bytesExpected=(await stat(filePath)).size}catch{return sendError(reply,req.id,404,"DOWNLOAD_NOT_FOUND","Offline file is unavailable")};const expiresAt=new Date(Date.now()+offlineDownloadTtlSeconds*1000);const token=await signOfflineDownload({sub:user.id,videoId:asset.id,deviceId:body.deviceId,expiresInSeconds:offlineDownloadTtlSeconds});return {videoAssetId:asset.id,downloadUrl:absoluteApiUrl(req,`/api/v1/media/${asset.id}/download?dt=${token}`),bytesExpected,headers:{},expiresAt:expiresAt.toISOString(),storage:"APP_PRIVATE_ONLY"}});
app.post("/api/v1/playback/sessions",{preHandler:authenticate,config:{rateLimit:{max:20,timeWindow:"1 minute"}}},async(req,reply)=>{const auth=(req as AuthRequest).auth;const body=z.object({videoId:z.string().uuid(),deviceId:z.string().min(8),riskSignals:z.array(z.string()).default([])}).parse(req.body);const user=await prisma.user.findUniqueOrThrow({where:{id:auth.sub}});if(user.status!=="ACTIVE")return sendError(reply,req.id,403,"ACCOUNT_BLOCKED","Playback unavailable");const asset=await prisma.videoAsset.findFirst({where:{state:"READY",OR:[{id:body.videoId},{movieId:body.videoId},{episodeId:body.videoId}]},include:{movie:true,episode:true}});if(!asset||!asset.manifestStorageKey)return sendError(reply,req.id,404,"VIDEO_UNAVAILABLE","Video is unavailable");if(asset.movie&&!(await canAccessMovie(user.id,asset.movie.id)))return sendError(reply,req.id,403,"TITLE_FORBIDDEN","This user is not allowed to watch this video");if(asset.movie&&(asset.movie.status!=="PUBLISHED"||!isCurrentlyAvailable(asset.movie)))return sendError(reply,req.id,403,"TITLE_UNAVAILABLE","This title is unavailable");if(asset.episode&&asset.episode.status!=="PUBLISHED")return sendError(reply,req.id,403,"TITLE_UNAVAILABLE","This episode is unavailable");if(config.DRM_PROVIDER==="widevine"&&(!config.WIDEVINE_LICENSE_URL||!asset.drmKeyId))return sendError(reply,req.id,503,"DRM_UNAVAILABLE","Protected playback is not configured for this asset");await prisma.playbackSession.updateMany({where:{userId:user.id,deviceId:body.deviceId,revokedAt:null},data:{revokedAt:new Date()}});const active=await prisma.playbackSession.count({where:{userId:user.id,revokedAt:null,expiresAt:{gt:new Date()}}});if(active>=config.MAX_CONCURRENT_STREAMS)return sendError(reply,req.id,409,"STREAM_LIMIT","Concurrent stream limit reached");const sid=randomUUID(),expiresAt=new Date(Date.now()+config.PLAYBACK_SESSION_TTL_SECONDS*1000);const token=await signPlayback({sub:user.id,sid,videoId:asset.id,deviceId:body.deviceId});await prisma.playbackSession.create({data:{id:sid,userId:user.id,videoAssetId:asset.id,deviceId:body.deviceId,expiresAt,riskSignals:body.riskSignals}});await prisma.watchHistory.create({data:{userId:user.id,videoAssetId:asset.id}});return {sessionId:sid,manifestUrl:absoluteApiUrl(req,`/api/v1/media/${asset.id}/manifest?pt=${token}`),headers:{"X-Playback-Session":sid},licenseUrl:config.DRM_PROVIDER==="widevine"?config.WIDEVINE_LICENSE_URL:undefined,videoAssetId:asset.id,watermark:{text:`${user.id.slice(0,4)}..${sid.slice(-4)}`,opacity:.22,moveEverySeconds:18},expiresAt:expiresAt.toISOString()}});
app.post("/api/v1/playback/progress",{preHandler:authenticate},async(req,reply)=>{const auth=(req as AuthRequest).auth;const body=z.object({videoAssetId:z.string().uuid(),positionSeconds:z.number().int().min(0),completed:z.boolean().default(false)}).parse(req.body);const asset=await prisma.videoAsset.findFirst({where:{OR:[{id:body.videoAssetId},{movieId:body.videoAssetId},{episodeId:body.videoAssetId}]}});if(!asset)return sendError(reply,req.id,404,"VIDEO_UNAVAILABLE","Video is unavailable");return prisma.watchProgress.upsert({where:{userId_videoAssetId:{userId:auth.sub,videoAssetId:asset.id}},create:{userId:auth.sub,videoAssetId:asset.id,positionSeconds:body.positionSeconds,completed:body.completed},update:{positionSeconds:body.positionSeconds,completed:body.completed,version:{increment:1}}})});
app.get("/api/v1/playback/progress",{preHandler:authenticate},async(req)=>prisma.watchProgress.findMany({where:{userId:(req as AuthRequest).auth.sub},orderBy:{updatedAt:"desc"},take:100}));
app.get("/api/v1/history",{preHandler:authenticate},async(req)=>prisma.watchHistory.findMany({where:{userId:(req as AuthRequest).auth.sub,removedAt:null},include:{videoAsset:{include:{movie:true,episode:true}}},orderBy:{watchedAt:"desc"},take:100}));
app.delete("/api/v1/history/:id",{preHandler:authenticate},async(req,reply)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;await prisma.watchHistory.updateMany({where:{id,userId:(req as AuthRequest).auth.sub},data:{removedAt:new Date()}});return reply.code(204).send()});
app.post("/api/v1/my-list",{preHandler:authenticate},async(req,reply)=>{const body=z.object({catalogId:z.string().uuid(),kind:z.enum(["MOVIE","SERIES"])}).parse(req.body);const userId=(req as AuthRequest).auth.sub;const item=await prisma.myListItem.upsert({where:{userId_catalogId:{userId,catalogId:body.catalogId}},create:{userId,...body},update:{kind:body.kind}});return reply.code(201).send(item)});
app.get("/api/v1/my-list",{preHandler:authenticate},async(req)=>prisma.myListItem.findMany({where:{userId:(req as AuthRequest).auth.sub},orderBy:{createdAt:"desc"}}));
