app.get("/api/v1/media/:id/manifest",async(req,reply)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;const query=z.object({pt:z.string().min(20).optional()}).parse(req.query);if(query.pt){try{const payload=await verifyPlayback(query.pt);if(payload.videoId!==id||payload.scope!=="playback")return sendError(reply,req.id,403,"FORBIDDEN","Playback token is not valid for this video")}catch{return sendError(reply,req.id,401,"TOKEN_INVALID","Playback session expired")}}else{await authenticate(req,reply);if(reply.sent)return}const asset=await prisma.videoAsset.findUnique({where:{id},include:{movie:true,episode:true}});if(!asset?.manifestStorageKey)return sendError(reply,req.id,404,"MANIFEST_NOT_FOUND","Manifest is unavailable");if(asset.movie&&(asset.movie.status!=="PUBLISHED"||!isCurrentlyAvailable(asset.movie)))return sendError(reply,req.id,403,"TITLE_UNAVAILABLE","This title is unavailable");if(asset.episode&&asset.episode.status!=="PUBLISHED")return sendError(reply,req.id,403,"TITLE_UNAVAILABLE","This episode is unavailable");const filePath=storagePathFor(asset.manifestStorageKey);if(!filePath)return sendError(reply,req.id,400,"MANIFEST_INVALID","Manifest path is invalid");let size=0;try{size=(await stat(filePath)).size}catch{return sendError(reply,req.id,404,"MANIFEST_NOT_FOUND","Manifest file is unavailable")};const range=req.headers.range;reply.header("accept-ranges","bytes");reply.header("cache-control","private, max-age=60");reply.header("content-type",contentTypeFor(asset.manifestStorageKey));if(range){const match=range.match(/bytes=(\d*)-(\d*)/);const startRaw=match?.[1],endRaw=match?.[2];const start=startRaw?Number(startRaw):0;const end=endRaw?Math.min(Number(endRaw),size-1):size-1;if(!Number.isFinite(start)||!Number.isFinite(end)||start<0||end<start||start>=size)return reply.code(416).header("content-range",`bytes */${size}`).send();reply.code(206).header("content-range",`bytes ${start}-${end}/${size}`).header("content-length",String(end-start+1));return reply.send(createReadStream(filePath,{start,end}))}reply.header("content-length",String(size));return reply.send(createReadStream(filePath))});
app.get("/api/v1/media/:id/download",async(req,reply)=>{const id=z.object({id:z.string().uuid()}).parse(req.params).id;const query=z.object({dt:z.string().min(20)}).parse(req.query);try{const payload=await verifyPlayback(query.dt);if(payload.videoId!==id||payload.scope!=="offline-download")return sendError(reply,req.id,403,"FORBIDDEN","Download token is not valid for this video")}catch{return sendError(reply,req.id,401,"TOKEN_INVALID","Offline download link expired")};const asset=await prisma.videoAsset.findUnique({where:{id},include:{movie:true,episode:true}});const key=asset?.manifestStorageKey;if(!asset||!key)return sendError(reply,req.id,404,"DOWNLOAD_NOT_FOUND","Offline file is unavailable");if(asset.movie&&(asset.movie.status!=="PUBLISHED"||!isCurrentlyAvailable(asset.movie)))return sendError(reply,req.id,403,"TITLE_UNAVAILABLE","This title is unavailable");if(asset.episode&&asset.episode.status!=="PUBLISHED")return sendError(reply,req.id,403,"TITLE_UNAVAILABLE","This episode is unavailable");const filePath=storagePathFor(key);if(!filePath)return sendError(reply,req.id,400,"DOWNLOAD_INVALID","Download path is invalid");let size=0;try{size=(await stat(filePath)).size}catch{return sendError(reply,req.id,404,"DOWNLOAD_NOT_FOUND","Offline file is unavailable")};const range=req.headers.range;const extension=path.extname(key)||".mp4";const filename=`${slugify(asset.movie?.title??asset.episode?.title??"securestream-video")}${extension}`;reply.header("accept-ranges","bytes");reply.header("cache-control","private, no-store");reply.header("content-disposition",`inline; filename="${filename}"`);reply.header("content-type",contentTypeFor(key));if(range){const match=range.match(/bytes=(\d*)-(\d*)/);const startRaw=match?.[1],endRaw=match?.[2];const start=startRaw?Number(startRaw):0;const end=endRaw?Math.min(Number(endRaw),size-1):size-1;if(!Number.isFinite(start)||!Number.isFinite(end)||start<0||end<start||start>=size)return reply.code(416).header("content-range",`bytes */${size}`).send();reply.code(206).header("content-range",`bytes ${start}-${end}/${size}`).header("content-length",String(end-start+1));return reply.send(createReadStream(filePath,{start,end}))}reply.header("content-length",String(size));return reply.send(createReadStream(filePath))});

